{"command": "cd /data/zrwang/auto-opt/utils/llvm-98800 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp 3091 3091

/// Fold:
///   %sel1 = select i1 %c1, T, F
///   %sel2 = select i1 %c1, F, T
///   %ret = select i1 %c2, %sel1, %sel2
/// into:
///   %xor = xor i1 %c1, %c2
///   %ret = select i1 %xor, F, T
static Instruction *foldSymmetricSelects(SelectInst &SI,
                                         InstCombiner::BuilderTy &Builder) {
  Value *Cond = SI.getCondition();
  Value *TrueVal = SI.getTrueValue();
  Value *FalseVal = SI.getFalseValue();

  // Both true and false values must be selects
  SelectInst *Sel1 = dyn_cast<SelectInst>(TrueVal);
  SelectInst *Sel2 = dyn_cast<SelectInst>(FalseVal);
  if (!Sel1 || !Sel2)
    return nullptr;

  // Both selects must have the same condition
  if (Sel1->getCondition() != Sel2->getCondition())
    return nullptr;

  // Sel1's true/false must be Sel2's false/true (swapped)
  if (Sel1->getTrueValue() != Sel2->getFalseValue() ||
      Sel1->getFalseValue() != Sel2->getTrueValue())
    return nullptr;

  // Profitability check: the inner selects should have single use
  // (the outer select we're processing)
  if (!Sel1->hasOneUse() || !Sel2->hasOneUse())
    return nullptr;

  // Create: xor %c1, %c2
  Value *XorCond = Builder.CreateXor(Sel1->getCondition(), Cond,
                                     SI.getName() + ".cond");

  // Create: select %xor, F, T (note: swapped to maintain correctness)
  return SelectInst::Create(XorCond, Sel1->getFalseValue(),
                            Sel1->getTrueValue(), SI.getName());
}

CODEEOF"}

